package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithHeader_ResultSetNotNull() throws SQLException {
        // Arrange
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        when(resultSet.getMetaData()).thenReturn(metaData);

        // Act
        CSVFormat result = csvFormat.withHeader(resultSet);

        // Assert
        assertNotNull(result);
        assertSame(csvFormat, result); // Since withHeader method returns the same instance
        verify(resultSet).getMetaData();
    }

    @Test
    public void testWithHeader_ResultSetNull() throws SQLException {
        // Arrange
        ResultSet resultSet = null;
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Act
        CSVFormat result = csvFormat.withHeader(resultSet);

        // Assert
        assertNotNull(result);
        assertSame(csvFormat, result); // Since withHeader method returns the same instance
    }
}
